"""Desktop launcher — generated by gs-app-pack.

Copy this file to your project root as app.py, then fill in the
SERVER STARTUP section.  Everything else is handled generically.

Supports three server modes (set in pack.config.ps1):
  function   -- calls module.func(host, port, cfg)
  uvicorn    -- calls uvicorn.run("module:app", host=host, port=port)
  subprocess -- spawns a shell command in a background process
"""
from __future__ import annotations

import argparse
import logging
import math
import socket
import struct
import subprocess
import sys
import threading
import time
from pathlib import Path

# ── PyInstaller bundle-path resolution ─────────────────────────────────────
if getattr(sys, "frozen", False):
    _BASE = Path(sys._MEIPASS)  # type: ignore[attr-defined]
else:
    _BASE = Path(__file__).resolve().parent

