log = logging.getLogger(__name__)

# ── CHANGE THESE to match your pack.config.ps1 ─────────────────────────────
_WIN_TITLE  = "My App"
_WIN_WIDTH  = 1400
_WIN_HEIGHT = 900
_WIN_BG     = "#07060a"

_DWM_CAPTION = 0x000A0607   # COLORREF 0x00BBGGRR for #07060a
_DWM_BORDER  = 0x0037AFD4   # #d4af37 gold
_DWM_TEXT    = 0x0095D1E8   # #e8d195 champagne

_ICON_BG   = "#07060a"
_ICON_RING = "#d4af37"
_ICON_SIZE = 32

_SERVER_HOST = "127.0.0.1"
_SERVER_PORT = 8790


